INSERT INTO public.workflow_entity VALUES ('[Send] finish', true, '[{"id": "7a9c666d-5f37-47b6-b534-52d13719cf92", "name": "Сообщение Перевод завершен", "type": "n8n-nodes-base.code", "position": [-880, 688], "parameters": {"jsCode": "const RUBLE_EXCHANGE_RATE = 79;\n\nconst billing_polza = Number($(''Данные document_jobs'').first().json.billing_polza) - Number($(''Billing Polza.ai'').first().json.amount);\n\nconst billing_neuro = -(Number($(''Данные document_jobs'').first().json.billing_neuro) - Number($(''Billing Neuro'').first().json.total_usage)) / 100;\n\nconst diff = DateTime.fromISO($(''Данные document_jobs'').first().json.created_at).diff(DateTime.fromISO($(''Данные document_jobs'').first().json.finished_at)).negate().toFormat(\"hh'':''mm'':''ss\");\n\nconst avv_time = DateTime.fromISO($(''Данные document_jobs'').first().json.created_at).diff(DateTime.fromISO($(''Данные document_jobs'').first().json.finished_at)).negate().toMillis() / (Number($(''Общее количество чанков'').first().json.chunks_total) || 1) / 1000;\n\nconst avv_cost = (billing_polza + billing_neuro * RUBLE_EXCHANGE_RATE) /  (Number($(''Общее количество чанков'').first().json.chunks_total) || 1);\n\nconst source = $(''Бинарные данные файлов'').first().json.source;\n\nconst message = {\n  message: `\n✅ <b>Перевод завершен!</b>\n\n📄 Документ (исходный): \n     ${$(''Данные document_jobs'').first().json.file_name}\n📄 Документ (с переводом): \n     ${$(''Данные document_jobs'').first().json.translated_file}\n\n💰 Итоговая стоимость Polza.ai: \n      ₽ ${ billing_polza.toFixed(2) }\n💰 Итоговая стоимость NeuroAPI: \n      $ ${ billing_neuro.toFixed(2) } (₽ ${(billing_neuro * RUBLE_EXCHANGE_RATE).toFixed(2).toString().replace(/\\B(?=(\\d{3})+(?!\\d))/g, \" \")})\n     \n🗓 Старт: <code>${ DateTime.fromISO($(''Данные document_jobs'').first().json.created_at).toFormat(\"dd.MM.yyyy HH:mm:ss\") }</code> \n⏱ Переведено за: <code>${ diff } (чч:мм:сс)</code>\n\n🔢 <b>Чанков переведено: ${$(''Общее количество чанков'').first().json.chunks_total}</b>\n⌛ Среднее время перевода 1 чанка: \n       ${ (avv_time).toLocaleString()} сек.\n💰 Средняя стоимость 1 чанка ≈\n       ₽ ${ avv_cost.toFixed(2) }\n\n📄 <b>Документ был поделен на:</b>\n       Главы - ${$(''Количество глав'').first().json.count}\n       Арки - ${$(''Количество арок'').first().json.count}\n\n${source !== ''telegram'' ? `<a href=\"${$(''Данные document_jobs'').first().json.web_chapters_link}\">Summary</a>\\n` : ''''}\n${source != ''telegram'' ? ''📁 <i>Файл сохранён на Google Drive</i>'' : ''''}\n`,\n  type: ''create''\n}\n\nif (source != ''telegram'')\n  message.button = {\n    name: ''📂 Открыть файл'',\n    text: $(''Данные document_jobs'').first().json.web_view_link || ''http://link.com''\n  }\n\nreturn { ...message }"}, "typeVersion": 2}, {"id": "0570cb3b-9c43-43f3-a384-c66c231c4cf3", "name": "Get row(s)", "type": "n8n-nodes-base.dataTable", "position": [-416, 384], "parameters": {"operation": "get", "dataTableId": {"__rl": true, "mode": "name", "value": "select_files"}}, "typeVersion": 1.1}, {"id": "2a2f9ff9-c8e8-4502-a1c9-d4a35e2c3dda", "name": "Данные document_jobs", "type": "n8n-nodes-base.postgres", "position": [-672, 160], "parameters": {"query": "SELECT * FROM document_jobs a, job_current b WHERE a.id =b.job_id;", "options": {}, "operation": "executeQuery"}, "credentials": {"postgres": {"id": "iGih4QSBWfmpkdGY", "name": "Postgres account"}}, "executeOnce": true, "retryOnFail": true, "typeVersion": 2.6, "alwaysOutputData": true}, {"id": "65674073-63e5-47d5-bbd8-0cf2b7964066", "name": "Общее количество чанков", "type": "n8n-nodes-base.postgres", "position": [-480, 160], "parameters": {"query": "SELECT count(*) as chunks_total FROM document_chunks WHERE job_id IN (SELECT job_id FROM job_current);", "options": {}, "operation": "executeQuery"}, "credentials": {"postgres": {"id": "iGih4QSBWfmpkdGY", "name": "Postgres account"}}, "executeOnce": true, "retryOnFail": true, "typeVersion": 2.6, "alwaysOutputData": 