VutdATd1MDS", "cachedResultUrl": "/workflow/2kztTVutdATd1MDS", "cachedResultName": "Анотация"}, "workflowInputs": {"value": {"job_id": "={{ $(''Данные document_jobs'').first().json.job_id }}"}, "schema": [{"id": "job_id", "type": "number", "display": true, "removed": false, "required": false, "displayName": "job_id", "defaultMatch": false, "canBeUsedToMatch": true}], "mappingMode": "defineBelow", "matchingColumns": ["job_id"], "attemptToConvertTypes": false, "convertFieldsToString": true}}, "typeVersion": 1.3}, {"id": "20d6d90c-df81-419b-a953-c4e6a766629e", "name": "Send a photo message", "type": "n8n-nodes-base.telegram", "position": [-1280, 688], "webhookId": "70f33601-c3d7-40ff-ace2-8e9db1027e1d", "parameters": {"file": "={{ $(''Анотация'').first().json.data[0].url }}", "chatId": "={{ $(''Get row(s)'').item.json.chat_id }}", "operation": "sendPhoto", "additionalFields": {"caption": "={{ $json.html_text }}", "parse_mode": "HTML"}}, "credentials": {"telegramApi": {"id": "V4jPr27PQcfRRHY9", "name": "Telegram account"}}, "typeVersion": 1.2}, {"id": "665cddcd-94a6-4ee6-ab4b-394c530fc925", "name": "Подготовка текста аннотации", "type": "n8n-nodes-base.code", "position": [-240, 384], "parameters": {"jsCode": "// Входной текст из предыдущего узла (Маркетолога)\nconst rawText = $(''Анотация'').first().json.text; \n\n// Разбиваем текст по разделителю \"---\"\nconst parts = rawText.split(''---'').map(p => p.replaceAll(''\\\\n'', '''').replace(''🔍'', '''').trim());\n\nlet htmlCaption = \"\";\n\nif (parts.length >= 3) {\n     // 1. Заголовок (делаем жирным и убираем скобки [])\n     const title = parts[0].replace(''['', '''').replace('']'', '''');\n     htmlCaption += `<b>${title.replaceAll(''\\n'', '''')}</b>\\n\\n`;\n\n     // 2. Аннотация (убираем маркер 📖, если он в начале)\n     const annotation = parts[1].replace(''📖'', '''').trim();\n     htmlCaption += `${annotation}\\n\\n`;\n\n     // 3. Хештеги\n     const hashtags = parts[2];\n     htmlCaption += `<code>${hashtags}</code>`;\n\n     // htmlCaption = htmlCaption.replaceAll(''\\n'', '''');\n } else {\n     // Если формат нарушен, просто упаковываем как есть\n     htmlCaption = rawText.replaceAll(/\\n/g, ''<br>'');\n }\n\n // ПРОВЕРКА ЛИМИТА TELEGRAM (1024 символа для фото)\n const TG_LIMIT = 1024;\n if (htmlCaption.length > TG_LIMIT) {\n     htmlCaption = htmlCaption.substring(0, TG_LIMIT - 3) + \"...\";\n }\n\n return {\n     html_text: htmlCaption\n };"}, "typeVersion": 2}]', '{"Get row(s)":{"main":[[{"node":"Подготовка текста аннотации","type":"main","index":0}]]},"Billing Polza.ai":{"main":[[{"node":"Billing Neuro","type":"main","index":0}]]},"Billing Neuro":{"main":[[{"node":"Данные document_jobs","type":"main","index":0}]]},"Данные document_jobs":{"main":[[{"node":"Общее количество чанков","type":"main","index":0}]]},"Общее количество чанков":{"main":[[{"node":"Количество законченных чанков","type":"main","index":0}]]},"Количество законченных чанков":{"main":[[{"node":"Количество глав","type":"main","index":0}]]},"Количество глав":{"main":[[{"node":"Количество арок","type":"main","index":0}]]},"Количество арок":{"main":[[{"node":"данные по чату","type":"main","index":0}]]},"Сообщение Перевод завершен":{"main":[[{"node":"Был ручной запуск перевода?","type":"main","index":0}]]},"Бинарные данные файлов":{"main":[[{"node":"Анотация","type":"main","index":0}]]},"Start Workflow":{"main":[[{"node":"Billing Polza.ai","type":"main","index":0}]]},"Удаляем сообщение c прогрессом":{"main":[[{"node":"Сообщение Перевод завершен","type":"main","index":0}]]},"данные по чату":{"main":[[{"node":"Бинарные данные файлов","type":"main","index":0}]]},"Был ручной запуск перевода?":{"main":[[{"node":"Send message1","type":"main","index":0}],[{"node":"Send message","type":"main","index":0}]]},"Анотация":{"main":[[{"node":"Get row(s)","type":"main","index":0}]]},"Send a photo message":{"main":[[{"node":"Удаляем сообщение c прогрессом","type":"main","index":0}]]},"Подготовка текста аннотации":{"main":[[{"node":"Send a photo message","type":"main","index":0}]]}}', '2026-03-29 07:51:39.181+00', '2026-04-05 08:46:10.076+00', '{"binaryMode": "separate", "executionOrder": "v1", "saveFailedExecution": "all", "saveManualExecutions": true, "saveExecutionProgress": "none", "saveDataSuccessExecution": "none"}', NULL, '{}', 'd46b045c-2c22-4d5a-9c02-6120b59ba618', 0, 'hoUl3ewz23AwAHlq', '{"templateCredsSetupCompleted":true}', 'YADn0DLCgXyPQPHF', false, 309, NULL, 'd46b045c-2c22-4d5a-9c02-6120b59ba618');
INSERT INTO public.workflow_entity VALUES ('[GET] /select_files', true, '[{"parameters":{"workflowInputs":{"values":[{"name":"id","type":"number"}]}},"type":"n8n-nodes-base.executeWorkflowTrigger","typeVersion":1.1,"position":[-2288,-48],"id":"ffdcde45-6088-4d21-8045-b18b72e7ce0b","name":"When Executed by Another Workflow"},{"parameters":{"operation":"executeQuery","query":"SELECT *\n  FROM\n    telegram_messages\n  WHERE id = {{ $(''When Executed by Another Workflow'').first().json.id }};","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[-1952,-48],"id":"81cce02e-5940-40d9-b481-ade942968899","name":"Получение данных о сообщении","executeOnce":true,"alwaysOutputData":true,"retryOnFail":true,"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"jsCode":"let icon_translate_file = ''❌'';\nlet icon_glossary = ''❌'';\nlet icon_glossary_make = ''❌'';\nlet icon_prompt = ''❎'';\nlet icon_post_prod = ''❎'';\n\nlet text_translate_file = ''Текст'';\nlet text_glossary = ''Глоссарий'';\nlet text_glossary_make = ''Создать Глоссарий'';\nlet text_prompt = ''Промт'';\nlet text_post_prod = ''Постредактирование'';\n\nconst buttons = [[{text: ''Отмена'', callback_data: ''cancel''}]];\nconst files = [];\n\nif ($(\"Get row(s)\").all().length) {\n  if ($input.first().json.translate_file) {\n    icon_translate_file = ''✅'';\n    text_translate_file = $input.first().json.translate_file.split(''_'')[0].replaceAll(''\"'','''');\n  }\n  \n  if ($input.first().json.glossary) {\n  icon_glossary = ''✅'';\n  text_glossary = $input.first().json.glossary.split(''_'')[0].replaceAll(''\"'','''');\n  } \n\n  if ($input.first().json.glossary_make) {\n    icon_glossary_make = ''✅'';\n    text_glossary_make = ''Создаем Глоссарий'';\n  } \n  \n  if ($input.first().json.promt) {\n  icon_prompt = ''✅'';\n  text_prompt = $input.first().json.promt.split(''_'')[0].replaceAll(''\"'','''');;\n  }\n\n  if ($input.first().json.PostProdaction) {\n  icon_prompt = ''✅'';\n  text_prompt = $input.first().json.PostProdaction.split(''_'')[0].replaceAll(''\"'','''');;\n  }\n  \n  if ($input.first().json.translate_file && ($input.first().json.glossary || $input.first().json.glossary_make)) {\n    buttons.push([{text: ''Начать перевод'', callback_data: ''start''}])\n  }\n}\n\nfiles.push([{text: `${icon_translate_file} ${text_translate_file}`, callback_data: ''ko''}]);\nif (icon_glossary === ''❌'' && icon_glossary_make === ''❌'') {\n    files.push([\n    {text: `${icon_glossary} ${text_glossary}`, callback_data: ''glossary''},\n    {text: `${icon_glossary_make} ${text_glossary_make}`, callback_data: ''glossary_make''}\n  ]);\n} else if (icon_glossary !== ''❌'') {\n    files.push([{text: `${icon_glossary} ${text_glossary}`, callback_data: ''glossary''}]);\n} else {\n    files.push([{text: `${icon_glossary_make} ${text_glossary_make}`, callback_data: ''glossary''}]);\n}\n\n\nif ($(''Получение данных о количестве промтов'').first().json.prompt > 0) {\n  files.push([{text: `${icon_prompt} ${text_prompt}`, callback_data: ''prompt''}]);\n  files.push([{text: `${icon_post_prod} ${text_post_prod}`, callback_data: ''post_prod''}]);\n}\n\nconst message = {\n  text: `Выбор файлов для перевода`,\n  chat_id: $(''Получение данных о сообщении'').first().json.message.from.id,\n  type: ''sendMessage'',\n  parse_mode: \"HTML\",\n  reply_markup: {\n    inline_keyboard: [\n      ...files,\n\n   ...buttons      ],\n  }\n}\nif ($input.first().json.message_id) {\n  message.message_id = $input.first().json.message_id\n  message.type = ''editMessageText'';\n}\nreturn { ...message }"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[-544,-80],"id":"536eb4f2-3930-4533-b32a-96619829c772","name":"Code in JavaScript1"},{"parameters":{"method":"POST","url":"=https://api.telegram.org/bot{{$credentials.telegramApi.accessToken}}/sendMessage","sendBody":true,"specifyBody":"json","jsonBody":"={{ JSON.stringify($json) }}","options":{}},"id":"6db8