INSERT INTO public.workflow_entity VALUES ('MOEX | Bootstrap Storage', false, '[{"id":"manual-trigger","name":"Manual Trigger","type":"n8n-nodes-base.manualTrigger","typeVersion":1,"position":[260,300],"parameters":{}},{"id":"init-postgres","name":"Init Postgres Schema","type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[560,300],"parameters":{"resource":"database","operation":"executeQuery","query":"CREATE TABLE IF NOT EXISTS moex_watchlist (\n  secid text PRIMARY KEY,\n  board text NOT NULL DEFAULT ''TQBR'',\n  market text NOT NULL DEFAULT ''shares'',\n  instrument_group text NOT NULL DEFAULT ''stocks'',\n  issuer_name text,\n  news_keywords text,\n  active boolean NOT NULL DEFAULT true,\n  created_at timestamptz NOT NULL DEFAULT now(),\n  updated_at timestamptz NOT NULL DEFAULT now()\n);\n\nCREATE TABLE IF NOT EXISTS moex_market_snapshot (\n  id bigserial PRIMARY KEY,\n  collected_at timestamptz NOT NULL DEFAULT now(),\n  secid text NOT NULL,\n  board text NOT NULL,\n  market text NOT NULL,\n  instrument_group text NOT NULL,\n  interval_code integer NOT NULL,\n  interval_name text NOT NULL,\n  from_date date,\n  till_date date,\n  candles_count integer NOT NULL DEFAULT 0,\n  latest_open numeric,\n  latest_close numeric,\n  latest_high numeric,\n  latest_low numeric,\n  latest_volume numeric,\n  change_pct numeric,\n  payload jsonb NOT NULL,\n  summary_text text,\n  source text NOT NULL DEFAULT ''moex_iss''\n);\n\nCREATE INDEX IF NOT EXISTS idx_moex_market_snapshot_secid_collected\n  ON moex_market_snapshot (secid, collected_at DESC);\nCREATE INDEX IF NOT EXISTS idx_moex_market_snapshot_interval\n  ON moex_market_snapshot (interval_name, collected_at DESC);\n\nCREATE TABLE IF NOT EXISTS moex_news_item (\n  id bigserial PRIMARY KEY,\n  collected_at timestamptz NOT NULL DEFAULT now(),\n  source text NOT NULL,\n  feed_url text,\n  external_id text NOT NULL,\n  published_at timestamptz,\n  title text NOT NULL,\n  link text,\n  summary text,\n  matched_secid text,\n  matched_keywords text,\n  payload jsonb NOT NULL,\n  UNIQUE (source, external_id)\n);\n\nCREATE INDEX IF NOT EXISTS idx_moex_news_item_secid_published\n  ON moex_news_item (matched_secid, published_at DESC);\n\nCREATE TABLE IF NOT EXISTS moex_analysis_report (\n  id bigserial PRIMARY KEY,\n  created_at timestamptz NOT NULL DEFAULT now(),\n  secid text,\n  instrument_group text,\n  report_type text NOT NULL,\n  model_name text,\n  summary_text text NOT NULL,\n  payload jsonb NOT NULL,\n  knowledge_source text\n);\n\nCREATE INDEX IF NOT EXISTS idx_moex_analysis_report_secid_created\n  ON moex_analysis_report (secid, created_at DESC);\n\nINSERT INTO moex_watchlist (secid, board, market, instrument_group, issuer_name, news_keywords, active)\nVALUES\n  (''SBER'', ''TQBR'', ''shares'', ''stocks'', ''Сбербанк'', ''сбер, сбербанк, sber'', true),\n  (''GAZP'', ''TQBR'', ''shares'', ''stocks'', ''Газпром'', ''газпром, gazprom, gazp'', true),\n  (''LKOH'', ''TQBR'', ''shares'', ''stocks'', ''Лукойл'', ''лукойл, lukoil, lkoh'', true)\nON CONFLICT (secid) DO UPDATE SET\n  board = EXCLUDED.board,\n  market = EXCLUDED.market,\n  instrument_group = EXCLUDED.instrument_group,\n  issuer_name = EXCLUDED.issuer_name,\n  news_keywords = EXCLUDED.news_keywords,\n  active = EXCLUDED.active,\n  updated_at = now();","options":{"queryBatching":"single"}},"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"id":"bootstrap-webhook","name":"Bootstrap Webhook","type":"n8n-nodes-base.webhook","typeVersion":2.1,"position":[260,460],"parameters":{"httpMethod":"POST","path":"moex-bootstrap-storage","responseMode":"lastNode","responseData":"firstEntryJson"},"webhookId":"6b8307bb-39b2-4c65-b0ae-a5f5ce00e1bc"}]', '{"Manual Trigger":{"main":[[{"node":"Init Postgres Schema","type":"main","index":0}]]},"Bootstrap Webhook":{"main":[[{"node":"Init Postgres Schema","type":"main","index":0}]]}}', '2026-04-17 17:01:46.361+00', '2026-04-17 19:01:22.093+00', '{"executionOrder":"v1","saveDataErrorExecution":"all","saveDataSuccessExecution":"none","saveManualExecutions":true,"saveExecutionProgress":true,"callerPolicy":"workflowsFromSameOwner","availableInMCP":false}', NULL, NULL, 'eee70f71-b45c-47ac-927b-4c63a923bc89', 1, 'j21mYQWh2XSPv0l2', NULL, 'FCsqLrchKiASqWpN', false, 10, NULL, NULL);
INSERT INTO public.workflow_entity VALUES ('[Перевод] Арка', true, '[{"parameters":{"text":"=Текущий rolling summary:\n{{ JSON.stringify($(''Получение данных для арки'').first().json.summary, null, 2) }}\n\nНовый переведённый фрагмент:\n{{ $(''Переведенный чанк'').first().json.result_text }}","schemaType":"fromJson","jsonSchemaExample":"{\n \"arc_summary_rolling\": \"...\",\n \"main_conflict\": \"...\",\n \"goals\": [\"...\"],\n \"key_changes\": [\"...\"],\n \"open_threads\": [\"...\"]\n}\n","options":{"systemPromptTemplate":"Ты обновляешь Rolling Summary текущей арки по итогам новой главы.\nВерни строго JSON формата:\n\nВходные данные:\n1) Текущее rolling summary арки (предыдущее значение).\n2) Summary новой главы (короткое, точное).\n3) (Опционально) список персонажей/терминов.\n\nОБЩИЕ ПРАВИЛА (жёстко):\nA) Используй только факты из входа. Ничего не выдумывай.\nB) Никаких интерпретаций и предположений. Запрещены слова/обороты:\n \"вероятно\", \"возможно\", \"скорее всего\", \"намекается\", \"по-видимому\",\n если в summary главы это не сказано напрямую.\nC) Не добавляй новых деталей мира, не объясняй устройство магии/политики, если этого нет в входе.\nD) Сохраняй максимальную стабильность: если новая глава не меняет пункт/поле — НЕ меняй его.\nE) Избегай синонимов и перефразирований без необходимости. Стабильные формулировки важнее \"красоты\".\nF) Никаких цитат из текста. Только нейтральные факты.\nG) Вывод — только JSON. Никакого дополнительного текста.\n\nКОНТРОЛЬ ДЛИНЫ:\n- arc_summary_rolling: 500–800 символов (строго).\n- main_conflict: 1–2 предложения, до 220 символов.\n- goals: 1–6 пунктов, каждый до 140 символов.\n- key_changes: 0–8 пунктов, каждый до 160 символов.\n- open_threads: 0–8 пунктов, каждый до 160 символов.\n\nСТИЛЬ ФОРМУЛИРОВОК:\n- Пиши в прошедшем времени, короткими фразами.\n- Каждый пункт — одно действие/изменение.\n- Не включай украшательства, эпитеты, оценочную лексику.\n\nСМЫСЛ ПОЛЕЙ (что именно туда кладём):\n\n1) arc_summary_rolling. \nЧто это:\n- Короткая \"сводка арки\" как единый текстовый абзац, который быстро вводит в курс.\n- Должен отвечать на вопросы: \"что за конфликт?\", \"кто основные действующие лица?\",\n \"какие важные события уже случились?\", \"к чему сейчас пришли?\", \"что осталось открытым?\".\n\nДОЛЖНО включать (в таком порядке, 4–6 предложений):\n(1) Описание главного конфликта арки (1 предложение).\n(2) Основные стороны/персонажи/фракции (1 предложение).\n(3) 1–2 ключевых поворотных события (1–2 предложения).\n(4) Текущее состояние/положение дел к последней главе (1 предложение).\n(5)1 предложение про главные открытые линии/риски (если есть).\n(6) Строго на русском языке\n\nНЕ ДОЛЖНО включать:\n- подробный пересказ всех событий по главам,\n- второстепенных персонажей, если они не влияют на конфликт,\n- микродетали сцен.\n\nПравило обновления:\n- Обновляй arc_summary_rolling только если новая глава:\n а) изменила состояние конфликта,\n б) заметно продвинула/изменила цели,\n в) закрыла или открыла важную нитку,\n г) привела к существенным потерям/обретениям.\n\n2) arc_state.main_conflict. \nЧто это:\n- Одна \"главная проблема\" арки, сформулированная максимально конкретно.\n- Это не тема и не мораль, а конфликт/противостояние/задача.\n\nДОЛЖНО:\n- быть одинаковым по смыслу от главы к главе, пока арка не закончилась.\n- включать участников/объект конфликта при наличии (\"герой против X\", \"нужно достичь Y, иначе Z\").\n\nНЕ ДОЛЖНО:\n- менять формулировку ради стиля,\n- становиться слишком общей (\"борьба добра и зла\"),\n- включать догадки о скрытых мотивах.\n\n3) arc_state.goals.\nЧто это:\n- Список текущих явных целей в рамках арки.\n- Цели должны быть измеримыми/проверяемыми (\"найти\", \"достичь\", \"защитить\", \"раскрыть\", \"сбежать\").\n\nДОЛЖНО включать:\n- цели главных действующих лиц (1–3 основных),\n- общие цели группы/фракции, если она важна.\n\nНЕ ДОЛЖНО включать:\n- эмоции (\"хочет быть счастливым\"),\n- общие желания без действий (\"хочет мира\"),\n- цели, которые уже выполнены (если выполнены — переносим в key_changes).\n\nПравила обновления goals:\n- Если цель выполнена → удалить из goals и добавить в key_changes (\"Цель X выполнена\").\n- Если цель изменилась → заменить формулировку, сохранив смысл.\n- Если появилась новая важная цель → добавить1 пункт.\n\n4) arc_state.key_changes.\nЧто это:\n- Ключевые изменения, которые произошли с начала арки до текущего момента.\n- Это \"факты прогресса\": что изменилось в расстановке сил, знаниях, ресурсах, отношениях.\n\nДОЛЖНО включать:\n- получение/потерю важного предмета/ресурса,\n- раскрытие важного факта/личности,\n- смену союза/конфликта,\n- серьёзные травмы/смерти/аресты (если они случились),\n- значимые решения (\"заключили сделку\", \"сбежали\", \"взорвали мост\").\n\nНЕ ДОЛЖНО включать:\n- мелкие события без последствий,\n- повторение уже известных изменений без новой информации.\n\nПравила обновления key_changes:\n- Добавляй только изменения текущей главы, если они \"ключевые\".\n- Не больше1 пункта на одно изменение.\n- Не переписывай старые пункты, если не появилось уточнение.\n\n5) arc_state.open_threads.\nЧто это:\n- Открытые линии, которые ещё не закрыты, и которые важны для арки.\n- Это конкретные \"вопросы/риски/обязательства\".\n\nДОЛЖНО включать:\n- угрозы, которые ещё актуальны,\n- незавершённые расследования,\n- обещания/долги/сроки,\n- \"кто/почему\" загадки, если они реально поставлены.\n\nНЕ ДОЛЖНО включать:\n- вопросы читателя/рецензента,\n- гипотезы без фактов,\n- \"возможные\" будущие события.\n\nПравила обновления open_threads:\n- Если нитка закрыта в новой главе → удалить её и добавить в key_changes (\"Нитка X закрыта/прояснена\").\n- Если нитка стала неактуальной → удалить без замены.\n- Если появилась новая важная нитка → добавить1 пункт.\n\nДЕТЕРМИНИЗМ / ПОВТОРЯЕМОСТЬ:\n- Если новая глава НЕ меняет main_conflict и goals — оставь их без изменений.\n- Изменяй минимум текста в arc_summary_rolling: не переставляй предложения местами без необходимости.\n- Не используй синонимы для ключевых терминов: один термин — одна форма.\n- Сортировка списков:\n goals: по важности (главная цель первой), затем по времени (ближайшая выше).\n open_threads: по срочности/риску.\n key_changes: в хронологическом порядке (самые ранние сверху, новые добавляй в конец)."}},"type":"@n8n/n8n-nodes-langchain.informationExtractor","typeVersion":1.2,"position":[416,160],"id":"c3ac4799-aa1a-4088-bc79-5fc219504183","name":"Rolling Summary арки","alwaysOutputData":false,"executeOnce":false,"retryOnFail":true,"onError":"continueErrorOutput"},{"parameters":{"text":"=CURRENT_ARC_STATE:\n{{ $(''Получение данных для арки'').first().json.summary ? JSON.stringify($(''Получение данных для арки'').first().json.summary) : `Отсутствует` }}\n\nNEW_CHAPTER_SUMMARY:\n{{ JSON.stringify($(''Подготовка данных по главе'').first().json.summary, null, 2) }}","schemaType":"fromJson","jsonSchemaExample":"{ \"starts_new_arc\": true, \"reason\": \"...\" }","options":{"systemPromptTemplate":"Ты — классификатор границы арки в романе.\n\nВход:\n1) ARC_DEFINITION — определение, что мы считаем аркой.\n2) CURRENT_ARC_STATE — текущее состояние арки (главный конфликт/цели/нитки).\n3) NEW_CHAPTER_SUMMARY — summary новой главы.\n\nЗадача:\nВернуть ОДНОЗНАЧНЫЙ ответ: эта глава начинает НОВУЮ арку или продолжает текущую.\n\nARC_DEFINITION (жёстко):\nАрка = непрерывная последовательность глав, объединённых ОДНИМ главным конфликтом/задачей и набором ключевых открытых нитей.\nНовая арка начинается ТОЛЬКО если выполнено хотя бы ОДНО из условий (A–C) и при этом НЕ выполнено условие (D):\n\nA) Главный конфликт текущей арки закрыт или больше не является главным (явно решён/отменён/потерял смысл).\nB) Появился новый главный конфликт/задача, который становится центральным и вытесняет прежний.\nC) Произошёл “перезапуск” ситуации: сменились одновременно (1) основная цель, (2) основной антагонист/сторона конфликта ИЛИ (3) место/сеттинг, и это явно обозначено как начало нового этапа истории.\n\nD) НЕ считать новой аркой:\n- смену локации без смены главного конфликта,\n- флэшбек/вставную сцену, после которой конфликт тот же,\n- временную паузу/передышку,\n- подготовку к следующему шагу в рамках того же конфликта,\n- появление нового персонажа, если конфликт тот же.\n\nПравила вывода:\n- Если ты не видишь условий A–C явно из NEW_CHAPTER_SUMMARY и CURRENT_ARC_STATE — ответ всегда \"продолжается\".\n- Не выдумывай причины и не используй предположения.\n\nТребования к reason:\n- 1–2 коротких предложения, строго факты из CURRENT_ARC_STATE и NEW_CHAPTER_SUMMARY.\n- Никаких предположений/интерпретаций. Запрещены слова: \"возможно\", \"вероятно\", \"кажется\", \"скорее всего\".\n- reason должен ссылаться на критерии ARC_DEFINITION буквами A/B/C/D:\n - если starts_new_arc = true → reason обязан указать, какой критерий сработал (A или B или C) и что именно в данных это подтверждает.\n - если starts_new_arc = false → reason обязан указать, что критерии A–C не подтверждены, либо что сработало исключение D (что это лишь смена локации/флэшбек/передышка/подготовка при том же конфликте).\n- Не повторяй целиком summary, только суть.\n- Переведи на русский язык.\n\nВерни строго JSON без пояснений"}},"type":"@n8n/n8n-nodes-langchain.informationExtractor","typeVersion":1.2,"position":[-432,160],"id":"21e5eb4e-fc39-4dc3-92ec-c47cc7fdca49","name":"Определение границ арки","executeOnce":false,"alwaysOutputData":false,"retryOnFail":true,"onError":"continueErrorOutput"},{"parameters":{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"37a0ba6a-bc8c-4d31-812c-f30a9a2bb209","leftValue":"={{ $(''Определение границ арки'').first().json.output.starts_new_arc }}","rightValue":true,"operator":{"type":"boolean","operation":"equals"}}],"combinator":"and"},"options":{}},"type":"n8n-nodes-base.if","typeVersion":2.3,"position":[48,144],"id":"98f04ff2-e157-4eac-aa9c-d375c87c644f","name":"Нчало новой арки?"},{"parameters":{"text":"=NEW_CHAPTER_SUMMARY:\n{{ JSON.stringify($(''Подготовка данных по главе'').first().json.summary,null,2) }}","schemaType":"fromJson","jsonSchemaExample":"{\n \"arc_summary_rolling\": \"...\",\n \"main_conflict\": \"...\",\n \"goals\": [\"...\"],\n \"key_changes\": [\"...\"],\n \"open_threads\": [\"...\"]\n}","options":{"systemPromptTemplate":"Ты создаёшь стартовое (инициализирующее) Summary новой арки романа.\n\nВход:\n- NEW_CHAPTER_SUMMARY: краткое фактическое summary главы, которая начинает новую арку.\n\nЗадача:\nСоздать \"arc_summary_rolling\" и \"arc_state\" для новой арки ТОЛЬКО на основе NEW_CHAPTER_SUMMARY.\nНичего не выдумывать. Если информации недостаточно — оставляй поле пустым или общим, но без догадок.\n\nЖёсткие правила:\n- Не добавляй фактов, которых нет во входе.\n- Не объясняй мир/мотивы, если это не сказано явно.\n- Формулировки стабильные, нейтральные, без художественных украшений.\n- Сохраняй имена/термины ровно как во входе.\n- Длина arc_summary_rolling: 4–6 предложений, суммарно 700–1200 символов.\n\nСМЫСЛ ПОЛЕЙ (что именно туда кладём):\n\n1) arc_summary_rolling. \nЧто это:\n- Короткая \"сводка арки\" как единый текстовый абзац, который быстро вводит в курс.\n- Должен отвечать на вопросы: \"что за конфликт?\", \"кто основные действующие лица?\",\n \"какие важные события уже случились?\", \"к чему сейчас пришли?\", \"что осталось открытым?\".\n\nДОЛЖНО включать (в таком порядке, 4–6 предложений):\n(1) Описание главного конфликта арки (1 предложение).\n(2) Основные стороны/персонажи/фракции (1 предложение).\n(3) 1–2 ключевых поворотных события (1–2 предложения).\n(4) Текущее состояние/положение дел к последней главе (1 предложение).\n(5) 1 предложение про главные открытые линии/риски (если есть).\n(6) Строго на русском языке\n\nНЕ ДОЛЖНО включать:\n- подробный пересказ всех событий по главам,\n- второстепенных персонажей, если они не влияют на конфликт,\n- микродетали сцен.\n\n2) arc_state.main_conflict. \nЧто это:\n- Одна \"главная проблема\" арки, сформулированная максимально конкретно.\n- Это не тема и не мораль, а конфликт/противостояние/задача.\n\nДОЛЖНО:\n- быть одинаковым по смыслу от главы к главе, пока арка не закончилась.\n- включать участников/объект конфликта при наличии (\"герой против X\", \"нужно достичь Y, иначе Z\").\n\nНЕ ДОЛЖНО:\n- менять формулировку ради стиля,\n- становиться слишком общей (\"борьба добра и зла\"),\n- включать догадки о скрытых мотивах.\n\n3) arc_state.goals.\nЧто это:\n- Список текущих явных целей в рамках арки.\n- Цели должны быть измеримыми/проверяемыми (\"найти\", \"достичь\", \"защитить\", \"раскрыть\", \"сбежать\").\n\nДОЛЖНО включать:\n- цели главных действующих лиц (1–3 основных),\n- общие цели группы/фракции, если она важна.\n\nНЕ ДОЛЖНО включать:\n- эмоции (\"хочет быть счастливым\"),\n- общие желания без действий (\"хочет мира\"),\n- цели, которые уже выполнены (если выполнены — переносим в key_changes).\n\n4) arc_state.key_changes.\nЧто это:\n- Ключевые изменения, которые произошли с начала арки до текущего момента.\n- Это \"факты прогресса\": что изменилось в расстановке сил, знаниях, ресурсах, отношениях.\n\nДОЛЖНО включать:\n- получение/потерю важного предмета/ресурса,\n- раскрытие важного факта/личности,\n- смену союза/конфликта,\n- серьёзные травмы/смерти/аресты (если они случились),\n- значимые решения (\"заключили сделку\", \"сбежали\", \"взорвали мост\").\n\nНЕ ДОЛЖНО включать:\n- мелкие события без последствий,\n- повторение уже известных изменений без новой информации.\n\n5) arc_state.open_threads.\nЧто это:\n- Открытые линии, которые ещё не закрыты, и которые важны для арки.\n- Это конкретные \"вопросы/риски/обязательства\".\n\nДОЛЖНО включать:\n- угрозы, которые ещё актуальны,\n- незавершённые расследования,\n- обещания/долги/сроки,\n- \"кто/почему\" загадки, если они реально поставлены.\n\nНЕ ДОЛЖНО включать:\n- вопросы читателя/рецензента,\n- гипотезы без фактов,\n- \"возможные\" будущие события."}},"type":"@n8n/n8n-nodes-langchain.informationExtractor","typeVersion":1.2,"position":[-256,496],"id":"fbb6cdc0-952f-45a0-bcc1-22d70dec91f0","name":"Cоздание стартового Summary новой арки","alwaysOutputData":false,"executeOnce":false,"retryOnFail":true,"onError":"continueErrorOutput"},{"parameters":{"numberInputs":3},"type":"n8n-nodes-base.merge","typeVersion":3.2,"position":[1280,128],"id":"11d51c9a-1005-4a8b-86e7-9020cde5b22d","name":"Merge1"},{"parameters":{"operation":"executeQuery","query":"-- Обновим данные о новой арке\nUPDATE \n    document_arcs \n  SET \n    end_chapter = {{ $(''Подготовка данных по главе'').first().json.chapter_number }},\n    summary = ''{{ JSON.stringify($(''Cоздание стартового Summary новой арки'').first().json.output).replaceAll(`''`, `''''`) }}'', \n    updated_at = now()\n  WHERE \n    id = {{ $(''Получение данных для арки'').first().json.current_arc }};","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[704,496],"id":"a28dffa7-6a19-421c-b2c2-c85e3673f23f","name":"Обновление данных о новой арке","alwaysOutputData":true,"executeOnce":true,"retryOnFail":true,"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"operation":"executeQuery","query":"-- Добавим причину перехода на новую арку\nUPDATE \n    document_arcs \n  SET \n    reason = ''{{ $(''Определение границ арки'').first().json.output.reason.replaceAll(`''`, `''''`) }}'', \n    updated_at = now() \n  WHERE id={{ $(''Получение данных для арки'').first().json.current_arc }};\n-- Добавим в таблицу с арками новую арку\n-- Обновим в job_current инфу об этой арке\nWITH arc AS (\n  INSERT INTO \n      document_arcs (job_id, arc_number, start_chapter, end_chapter)\n    VALUES \n      ({{ $(''Переведенный чанк'').first().json.job_id }}, \n      (SELECT MAX(arc_number)+1 FROM document_arcs WHERE job_id = {{ $(''Переведенный чанк'').first().json.job_id }}), \n      {{ $(''Подготовка данных по главе'').first().json.chapter_number }}, \n      {{ $(''Подготовка данных по главе'').first().json.chapter_number }}) \n    RETURNING id\n)\nUPDATE job_current SET current_arc=(SELECT * FROM arc LIMIT 1)","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[384,-16],"id":"6d65d23e-41d3-48ef-8ee2-7d57fc9a4eca","name":"Добавление новой арки","alwaysOutputData":true,"executeOnce":true,"retryOnFail":true,"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"operation":"executeQuery","query":"-- Обновим данные о текущей арке\nUPDATE \n    document_arcs \n  SET \n    end_chapter = {{ $(''Подготовка данных по главе'').first().json.chapter_number }}, \n    summary = ''{{ JSON.stringify($(''Rolling Summary арки'').first().json.output).replaceAll(`''`, `''''`) }}'', \n    updated_at = now() \n  WHERE \n    id = {{ $(''Получение данных для арки'').first().json.current_arc }};","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[864,144],"id":"d7907aff-7c45-4752-937c-78484f2758b0","name":"Обновление Suumary арки","alwaysOutputData":true,"executeOnce":true,"retryOnFail":true,"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"workflowInputs":{"values":[{"name":"id_chunk","type":"number"}]}},"type":"n8n-nodes-base.executeWorkflowTrigger","typeVersion":1.1,"position":[-1984,320],"id":"4e4ce390-afa8-4985-ab3a-8504c8b23b6d","name":"When Executed by Another Workflow"},{"parameters":{"operation":"executeQuery","query":"SELECT * FROM document_chunks WHERE id = {{ $json.id_chunk }}","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[-1776,320],"id":"727ff58d-5478-4069-a72e-cc2d29ae23ea","name":"Переведенный чанк","executeOnce":true,"alwaysOutputData":true,"retryOnFail":true,"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"schema":{"__rl":true,"mode":"list","value":"public"},"table":{"__rl":true,"value":"document_log","mode":"list","cachedResultName"