":{"conditions":[{"condition":"isNotEmpty"}]},"columns":{"mappingMode":"defineBelow","value":{"message_start":"=0"},"matchingColumns":[],"schema":[{"id":"translate_file","displayName":"translate_file","required":false,"defaultMatch":false,"display":true,"type":"string","readOnly":false,"removed":true},{"id":"glossary","displayName":"glossary","required":false,"defaultMatch":false,"display":true,"type":"string","readOnly":false,"removed":true},{"id":"promt","displayName":"promt","required":false,"defaultMatch":false,"display":true,"type":"string","readOnly":false,"removed":true},{"id":"message_id","displayName":"message_id","required":false,"defaultMatch":false,"display":true,"type":"number","readOnly":false,"removed":true},{"id":"chat_id","displayName":"chat_id","required":false,"defaultMatch":false,"display":true,"type":"string","readOnly":false,"removed":true},{"id":"glossary_make","displayName":"glossary_make","required":false,"defaultMatch":false,"display":true,"type":"boolean","readOnly":false,"removed":true},{"id":"message_start","displayName":"message_start","required":false,"defaultMatch":false,"display":true,"type":"number","readOnly":false,"removed":false}],"attemptToConvertTypes":false,"convertFieldsToString":false},"options":{}},"type":"n8n-nodes-base.dataTable","typeVersion":1.1,"position":[592,96],"id":"0ec8bd0f-a511-4d91-b709-3da14b261985","name":"Удалим id"}]', '{"Start Workflow":{"main":[[{"node":"Данные по задаче","type":"main","index":0}]]},"Отправка сообщения":{"main":[[{"node":"Сохраним id","type":"main","index":0}]]},"Формируем сообщение":{"main":[[{"node":"Отправка сообщения","type":"main","index":0}]]},"Данные по задаче":{"main":[[{"node":"Это послать сообщение?","type":"main","index":0}]]},"Это послать сообщение?":{"main":[[{"node":"Формируем сообщение","type":"main","index":0}],[{"node":"Удаление сообщения","type":"main","index":0}]]},"Удаление сообщения":{"main":[[{"node":"Удалим id","type":"main","index":0}]]}}', '2026-03-28 05:41:53.574+