INSERT INTO public.workflow_entity VALUES ('sub_lightrag_api', true, '[{"parameters":{"jsCode":"const action = $input.first().json.action;\nlet url = '''';\nlet method = '''';\nlet body = {};\n\nswitch (action) {\n  case ''clear'':\n    method=''DELETE'';\n    url=''https://lightrag.bigalexn8n.ru/documents'';\n    break;\n  case ''insertText'':\n    method=''POST'';\n    url=''https://lightrag.bigalexn8n.ru/documents/text'';\n    body.text = $input.first().json.text;\n    body.file_source = $input.first().json.meta_data;\n    break;\n  case ''deleteChunks'':\n    method=''DELETE'';\n    url=''https://lightrag.bigalexn8n.ru/documents/delete_document'';\n    body.doc_ids = [];\n    body.delete_file = true;\n    body.delete_llm_cache = true;\n    break;\n  case ''insertTexts'':\n    method=''POST'';\n    url=''https://lightrag.bigalexn8n.ru/documents/texts'';\n    body.texts = $input.first().json.texts;\n    body.file_sources = JSON.parse($input.first().json.meta_data);\n    break;\n  case ''query'':\n    method=''POST'';\n    url=''https://lightrag.bigalexn8n.ru/query'';\n    body.query=`Проанализируй корейский текст ниже. Найди в базе знаний факты о персонажах, их поле, локациях и терминах.\n\n### ПРАВИЛА ОФОРМЛЕНИЯ СПРАВКИ:\n1. Важно: ВСЕ имена и названия должны быть ТОЛЬКО на русском языке. \n2. Если есть имя на корейском языке - транслитерируй его на русский язык самостоятельно (например, 이사영 -> И Саён). \n3. НЕ оставляй корейских символов в итоговом списке.\n4. Объединяй все факты об одном персонаже в один пункт.\n5. НЕ пиши фразы типа ''персонаж, к которому относится имя''. Пиши сразу суть.\n6. Если факта нет - не выдумывай, исключи из ответа\n\n### ФОРМАТ ОТВЕТА (СПИСОК):\n - [Имя]: [пол, краткая роль и характеристика]\n - [Связь]: [отношения между героями на русском]\n - [Факт]: [событие на русском]\n - [Локация]: [описание локации]`;\n    body.mode = \"mix\";\n    body.top_k = 20;\n    body.max_total_tokens = 1500;\n    body.response_type = ''Single Paragraph'';\n    body.user_prompt = `Текст:\n    ${$input.first().json.text}`;\n    break;\n  case ''summary'':\n    method=''POST'';\n    url=''https://lightrag.bigalexn8n.ru/query'';\n    body.mode = \"global\";\n    body.top_k = 40;\n    body.max_total_tokens = 4000;\n    body.response_type = ''Single Paragraph'';\n    body.query = `### ЗАДАЧА: СИНТЕЗ СУТИ КНИГИ\nПроанализируй ВЕСЬ граф знаний этой книги. Игнорируй мелкие диалоги и временные события. \nВыдели глобальную структуру сюжета и ключевые образы.\n\n### ЧТО НУЖНО ВЫДЕЛИТЬ:\n1. КЛЮЧЕВАЯ КОНЦЕПЦИЯ: В чем главная идея мира? (Например: система уровней в реальности, месть падшего бога, выживание в космосе).\n2. ГЛАВНЫЕ ГЕРОИ (АРХЕТИП): Краткое описание личности героев и их главные визуальные особенности (шрам, глаза, броня). Количество героев: 1 или 2.\n3. ГЛАВНЫЙ КОНФЛИКТ: Против чего или кого сражается мир или герои?\n4. КЛЮЧЕВАЯ ЛОКАЦИЯ: Где происходит основное действие, задающее атмосферу?\n5. ЦВЕТОВАЯ ПАЛИТРА И СТИЛЬ: Какое настроение у этой истории? (Мрачное, золотое, неоновое, кровавое).\n\nВЫДАЙ ОТВЕТ СТРОГО СПИСКОМ ТЕЗИСОВ НА РУССКОМ ЯЗЫКЕ. \nМинимум воды, максимум смысла.\n`;\n    break;\n  default:\n    break;\n}\nreturn {url, method, body}"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[-272,0],"id":"69a9e608-222c-48ab-a4d1-673cfd07fc92","name":"Code in JavaScript"},{"parameters":{"workflowInputs":{"values":[{"name":"action"},{"name":"text"},{"name":"texts","type":"array"},{"name":"meta_data"}]}},"type":"n8n-nodes-base.executeWorkflowTrigger","typeVersion":1.1,"position":[-448,0],"id":"ffd9ce3c-ff28-40dd-9e04-af1ba1b179d5","name":"Start Workflow","alwaysOutputData":true},{"parameters":{"method":"={{ $json.method }}","url":"={{ $json.url }}","authentication":"genericCredentialType","genericAuthType":"httpHeaderAuth","sendHeaders":true,"headerParameters":{"parameters":[{"name":"accept","value":"application/json"},{"name":"Content-Type","value":"application/json"}]},"options":{}},"id":"28a4e7ec-0243-4a6f-9e7d-a2486e771049","name":"LightRAG API without body","type":"n8n-nodes-base.httpRequest","typeVersion":4.1,"position":[288,-80],"credentials":{"httpHeaderAuth":{"id":"04F0dXlIVNesjJse","name":"LightRag"}},"continueOnFail":true},{"parameters":{"method":"={{ $(''Code in JavaScript'').first().json.method }}","url":"={{ $(''Code in JavaScript'').first().json.url }}","authentication":"genericCredentialType","genericAuthType":"httpHeaderAuth","sendHeaders":true,"headerParameters":{"parameters":[{"name":"accept","value":"application/json"},{"name":"Content-Type","value":"application/json"}]},"sendBody":true,"specifyBody":"json","jsonBody":"={{ JSON.stringify($(''Code in JavaScript'').first().json.body) }}","options":{}},"id":"70b1cd48-76c1-43f6-ae38-21ca034d5846","name":"LightRAG API with body","type":"n8n-nodes-base.httpRequest","typeVersion":4.1,"position":[288,80],"credentials":{"httpHeaderAuth":{"id":"04F0dXlIVNesjJse","name":"LightRag"}},"continueOnFail":true},{"parameters":{"rules":{"values":[{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"c3acfceb-72e7-41c6-9810-bad66dbe0518","leftValue":"={{ $(''Start Workflow'').first().json.action }}","rightValue":"clear","operator":{"type":"string","operation":"equals","name":"filter.operator.equals"}}],"combinator":"and"},"renameOutput":true,"outputKey":"clear"},{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"67146ea5-a541-4779-be1f-f4bb9ad79ca4","leftValue":"={{ $(''Start Workflow'').first().json.action }}","rightValue":"insertText","operator":{"type":"string","operation":"equals","name":"filter.operator.equals"}}],"combinator":"and"},"renameOutput":true,"outputKey":"insertText"},{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"0692182d-f129-4502-907a-dcd68f7d739a","leftValue":"={{ $(''Start Workflow'').first().json.action }}","rightValue":"insertTexts","operator":{"type":"string","operation":"equals","name":"filter.operator.equals"}}],"combinator":"and"},"renameOutput":true,"outputKey":"insertTexts"},{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"c0c3754b-6a52-4d77-ad22-9a2a26aa5c80","leftValue":"={{ $(''Start Workflow'').first().json.action }}","rightValue":"query","operator":{"type":"string","operation":"equals","name":"filter.operator.equals"}}],"combinator":"and"},"renameOutput":true,"outputKey":"query"},{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"d0972c98-ded2-420c-8a6e-261f93c6677d","leftValue":"={{ $(''Start Workflow'').first().json.action }}","rightValue":"summary","operator":{"type":"string","operation":"equals","name":"filter.operator.equals"}}],"combinator":"and"},"renameOutput":true,"outputKey":"summary"},{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"8cc12f2e-6106-4873-b78d-65414040c8bf","leftValue":"={{ $(''Start Workflow'').first().json.action }}","rightValue":"","operator":{"type":"string","operation":"empty","singleValue":true}}],"combinator":"and"},"renameOutput":true,"outputKey":"exit"}]},"options":{}},"type":"n8n-nodes-base.switch","typeVersion":3.4,"position":[-112,-64],"id":"23345167-6ba7-4e71-84f4-6de3b9144633","name":"Switch"}]', '{"Start Workflow":{"main":[[{"node":"Code in JavaScript","type":"main","index":0}]]},"Code in JavaScript":{"main":[[{"node":"Switch","type":"main","index":0}]]},"LightRAG API with body":{"main":[[]]},"Switch":{"main":[[{"node":"LightRAG API without body","type":"main","index":0}],[{"node":"LightRAG API with body","type":"main","index":0}],[{"node":"LightRAG API with body","type":"main","index":0}],[{"node":"LightRAG API with body","type":"main","index":0}],[{"node":"LightRAG API with bod