INSERT INTO public.workflow_entity VALUES ('Получение сообщения', true, '[{"parameters":{"operation":"executeQuery","query":"-- Если вдруг нет таблицы с сообщениями от бота, создаем ее\nCREATE TABLE IF NOT EXISTS telegram_messages (\n  id SERIAL PRIMARY KEY,\n  chat TEXT,\n  message JSON,\n  callback_data TEXT,\n  date_time TIMESTAMP WITH TIME ZONE DEFAULT now(),\n  type TEXT,\n  lang TEXT,\n  is_translate BOOLEAN DEFAULT FALSE\n);","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[-400,176],"id":"39223e8e-1d15-4333-9df6-7677d5793e12","name":"Обновление данных о сообщении в бд","executeOnce":true,"alwaysOutputData":true,"retryOnFail":true,"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"rules":{"values":[{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"leftValue":"={{ $(''Loop Over Items'').item.json.body.message.document.file_name }}","rightValue":"","operator":{"type":"string","operation":"exists","singleValue":true},"id":"3922df1f-e954-4c1a-9540-17a5552024a5"}],"combinator":"and"},"renameOutput":true,"outputKey":"FILE"},{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"f4524f45-e475-4773-b93a-b72777f3192d","leftValue":"={{ $(''Loop Over Items'').item.json.body.file_id }}","rightValue":"/select_files","operator":{"type":"string","operation":"notEmpty","singleValue":true}}],"combinator":"and"},"renameOutput":true,"outputKey":"SELECT FILES"}]},"options":{}},"type":"n8n-nodes-base.switch","typeVersion":3.4,"position":[-224,176],"id":"87c8c3be-8279-4040-a950-c7138ec42dfb","name":"Switch"},{"parameters":{"workflowId":{"__rl":true,"value":"sLo74sUgMdcJEmxJoRJQ-","mode":"list","cachedResultUrl":"/workflow/sLo74sUgMdcJEmxJoRJQ-","cachedResultName":"[GET] Document"},"workflowInputs":{"mappingMode":"defineBelow","value":{"id":"={{ $json.id }}"},"matchingColumns":[