INSERT INTO public.workflow_entity VALUES ('[Перевод] Обработка ошибки', true, '[{"parameters":{"operation":"executeQuery","query":"UPDATE \n    job_current \n  SET \n    count_error_chunks = {{ $json.count_error_chunks }}, \n    error_text = ''{{ $json.error_text.replaceAll(`''`,`''''`) }}''\n  WHERE \n    job_id = {{ $(''Переведенный чанк'').first().json.job_id }};\n\n-- пошлем сообщение что ошибка при переводе очередной части чанков\nINSERT INTO telegram_send_message (template) VALUES (''error_processing'');","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[-304,48],"id":"3defb5ac-f020-483d-8d96-a59f4c4f9a50","name":"Обновление данных текущей задачи из-за ошибки","credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"jsCode":"const HOW_OFTEN_ERROR_TRANSLATE = 3;\n\nlet is_stop_translate = false;\nlet count_error_chunks = $(''Чтение данных текущей задачи'').first().json.count_error_chunks;\ncount_error_chunks++;\n\nif (count_error_chunks % HOW_OFTEN_ERROR_TRANSLATE === 0) {\n  is_stop_translate = true\n}  \n\nlet error_text = `\nЧанк: ${$(''Переведенный чанк'').first().json.chunk_index}\nГлава: ${$(''Переведенный чанк'').first().json.chapter_number}\nНода: ${$(''Чтение данных текущей задачи'').last().json.node}\nОшибка: ${$(''Чтение данных текущей задачи'').last().json.log}\n`;\n\n\nreturn { count_error_chunks, error_text, is_stop_translate }"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[-512,48],"id":"1a8651f4-0296-451f-85f7-5a3dfd2226c4","name":"Вычисление данных для формирования сообщения"},{"parameters":{},"type":"n8n-nodes-base.wait","typeVersion":1.1,"position":[-448,288],"id":"17c18a3d-a3b1-4a23-8b80-6d8b0e9abb91","name":"Ждем 5 сек","webhookId":"50004e8f-e8de-4f12-9d31-9325128f7a77"},{"parameters":{"conditions":{"options":{"caseSensitive":true,"leftValue":"","typeValidation":"strict","version":3},"conditions":[{"id":"0fe63bca-5c30-4848-a805-ef6743c4bbb1","leftValue":"={{ $jso