eQuery","query":"  SELECT  * \n    FROM  document_log l, job_current j \n   WHERE  l.job_id = j.job_id \nORDER BY  l.id","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[-720,48],"id":"8154bccd-a60c-48bb-8618-13b1bfef2f17","name":"Чтение данных текущей задачи","executeOnce":true,"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"operation":"executeQuery","query":"UPDATE \n    document_jobs \n  SET \n    status = ''wait''  \n  WHERE \n    id = {{ $(''Переведенный чанк'').first().json.job_id }};\n\n-- пошлем сообщение что перевод остановлен и требуется подтверждение продолжения\nINSERT INTO telegram_send_message (template) VALUES (''wait_processing'');","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[-688,288],"id":"3a3a9e30-a6ac-47ab-b5b6-17e99e4d2cf9","name":"Оповещение об остановке перевода","retryOnFail":true,"alwaysOutputData":true,"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"mode":"chooseBranch"},"type":"n8n-nodes-base.merge","typeVersion":3.2,"position":[336,192],"id":"c1b58231-a7c4-407c-9a26-e65c3ec0482f","name":"Merge"},{"parameters":{"operation":"executeQuery","query":"SELECT \n    * \n  FROM \n    document_jobs d, \n    job_current c \n  WHERE \n    d.id = c.job_id;","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[-272,288],"id":"d21164b8-811d-466f-ae46-00c18efe84af","name":"Получение данных о подтверждении","credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"content":"## 📄 Суть сценария\nОбработчик текста. Взаимодействует с LLM (DeepSeek/Qwen) для перевода фрагментов новелл.\n\n🧪 **Оптимизация:** 💡 Стоит добавить проверку лимитов (Billing) перед отправкой тяжелых запросов.\n\n---\n*Gen by Gemini CLI*","height":250,"width":500,"color":6},"id":"desc-sticker-ImJp","name":"Documentation","type":"n8n-nodes-base.stickyNote","typeVersion":1,