INSERT INTO public.workflow_entity VALUES ('[Send] processing', true, '[{"id": "5ccb8d3f-76d1-4feb-9a98-4af48e4ce545", "name": "Данные document_jobs", "type": "n8n-nodes-base.postgres", "position": [-256, 320], "parameters": {"query": "SELECT * FROM document_jobs a, job_current b WHERE a.id =b.job_id;", "options": {}, "operation": "executeQuery"}, "credentials": {"postgres": {"id": "iGih4QSBWfmpkdGY", "name": "Postgres account"}}, "executeOnce": true, "retryOnFail": true, "typeVersion": 2.6, "alwaysOutputData": true}, {"id": "27e4020f-e471-4a28-b2df-bed8bcaaec19", "name": "Общее количество чанков", "type": "n8n-nodes-base.postgres", "position": [-64, 320], "parameters": {"query": "SELECT count(*) as chunks_total FROM document_chunks WHERE job_id IN (SELECT job_id FROM job_current);", "options": {}, "operation": "executeQuery"}, "credentials": {"postgres": {"id": "iGih4QSBWfmpkdGY", "name": "Postgres account"}}, "executeOnce": true, "retryOnFail": true, "typeVersion": 2.6, "alwaysOutputData": true}, {"id": "9e5273ce-b1ba-41f1-a450-9dd693617f32", "name": "Количество законченных чанков", "type": "n8n-nodes-base.postgres", "position": [128, 320], "parameters": {"query": "SELECT count(*) as chunks_done FROM document_chunks WHERE job_id IN (SELECT job_id FROM job_current) AND status=''done'';", "options": {}, "operation": "executeQuery"}, "credentials": {"postgres": {"id": "iGih4QSBWfmpkdGY", "name": "Postgres account"}}, "executeOnce": true, "retryOnFail": true, "typeVersion": 2.6, "alwaysOutputData": true}, {"id": "542a645e-aabd-463d-b0fa-7da72fd96312", "name": "Сообщение Перевод в процессе", "type": "n8n-nodes-base.code", "position": [-752, 640], "parameters": {"jsCode": "const RUBLE_EXCHANGE_RATE = 79;\n\nconst billing_polza = Number($(''Данные document_jobs'').first().json.billing_polza) - Number($(''Billing Polza.ai'').first().json.amount);\nconst billing_neuro = -(Number($(''Данные document_jobs'').first().json.billing_neuro) - Number($(''Billing Neuro'').first().json.total_usage)) / 100;\n\nconst startedAtMs = DateTime.fromISO($(''Данные document_jobs'').first().json.created_at);\nconst diff = startedAtMs.diffNow().negate().toFormat(\"hh'':''mm'':''ss\")\n\nconst done = Number($(''Количество законченных чанков'').first().json.chunks_done);\nconst total = Number($(''Общее количество чанков'').first().json.chunks_total);\n// const done = Math.floor(Math.random() * total);\nconst ratio = Math.min(1, Math.max(0, done / total));\n\nconst startedAt = startedAtMs.toFormat(\"dd.MM.yyyy HH:mm:ss\");\n\nconst width =20;\nconst filled = Math.round(ratio * width);\nconst bar = ''█''.repeat(filled) + ''░''.repeat(width - filled);\n\nreturn {\n  message: `\n🔄 <b>Перевод в процессе</b>\n\n📄 Документ: ${$(''Данные document_jobs'').first().json.file_name}\n<b>🗓 Старт:</b> <code>${ startedAt }</code> \n<b>⏱ Прошло: <code>${ diff }</code></b>\n<b>📊 Прогресс:</b> <code>${ `${bar} ${Math.floor(ratio*100)}%` }</code> \n<b>🧩 Текущий чанк: <code>${ done }/${ total }</code></b>\n💰 Потрачено на Polza.ai: \n      ₽ ${ billing_polza.toFixed(2) }\n💰 Потрачено на NeuroAPI: \n      ₽ ${(billing_neuro * RUBLE_EXCHANGE_RATE).toFixed(2).toString().replace(/\\B(?=(\\d{3})+(?!\\d))/g, \" \")}\n\n<i>Сообщение сгенерировано автоматически.</i>\n  `,\n  type: ''edit'',\n  button: {}\n} "}, "typeVersion": 2}, {"id": "6e64f5c7-7cf9-4f7f-8d6f-e813aea20de3", "name": "Billing Polza.ai", "type": "n8n-nodes-base.httpRequest", "onError": "continueRegularOutput", "position": [-656, 320], "parameters": {"url": "https://polza.ai/api/v1/balance", "options": {"timeout": 1000}, "sendHeaders": true, "headerParameters": {"parameters": []}, "authentication": "genericCredentialType", "genericAuthType": "httpHeaderAuth"}, "credentials": {"httpHeaderAuth": {"id": "3dfmGKUa1Q01H200", "name": "Billing Polza Header"}}, "typeVersion": 4.4}, {"id": "baf8993c-1303-463b-a220-844265f8ad3d", "name": "Billing Neuro", "type": "n8n-nodes-base.httpRequest", "onError": "continueRegularOutput", "position": [-448, 320], "parameters": {"url": "https://neuroapi.host/v1/dashboard/billing/usage", "options": {"timeout": 1000}, "sendHeaders": true, "headerParameters": {"parameters": []}, "authentication": "genericCredentialType", "genericAuthType": "httpHeaderAuth"}, "credentials": {"httpHeaderAuth": {"id": "GIoKsxpIObYHo6Nm", "name": "Billing Neuro Header"}}, "typeVersion": 4.4}, {"id": "6c0a32c7-9cc8-44db-a822-785b3fe9206a", "name": "When Executed by Another Workflow", "type": "n8n-nodes-base.executeWorkflowTrigger", "position": [-1008, 320], "parameters": {"workflowInputs": {"values": [{"name": "qwerty"}]}}, "typeVersion": 1.1}, {"id": "83b54a22-b281-4fff-9ba4-38e2bb0c5ec2", "name": "Редактируем текст сообщения", "type": "n8n-nodes-base.telegram", "position": [-240, 752], "webhookId": "ee3317ee-e386-4133-8122-dcb431c6fcfc", "parameters": {"text": "={{ $json.message }}", "chatId": "={{ $(''Get row(s)'').item.json.chat_id }}", "messageId": "={{ $(''данные по чату'').first().json.message_id }}", "operation": "editMessageText", "additionalFields": {"parse_mode": "HTML"}}, "credentials": {"telegramApi": {"id": "V4jPr27PQcfRRHY9", "name": "Telegram account"}}, "typeVersion": 1.2}, {"id": "4dd2d334-f14a-47ac-bc81-d1b4030c3973", "name": "первое сообщение для редактирования?", "type": "n8n-nodes-base.if", "position": [-528, 640], "parameters": {"options": {}, "conditions": {"options": {"version": 3, "leftValue": "", "caseSensitive": true, "typeValidation": "loose"}, "combinator": "and", "conditions": [{"id": "0b4f8857-12e6-4790-9e12-f1ec168902b2", "operator": {"type": "string", "operation": "empty", "singleValue": true}, "leftValue": "={{ $(''данные по чату'').first().json.message_id }}", "rightValue": ""}]}, "looseTypeValidation": true}, "typeVersion": 2.3}, {"id": "df765050-e7ce-4d4b-8210-d546773e5184", "name": "Посылаем сообщение", "type": "n8n-nodes-base.telegram", "position": [-240, 544], "webhookId": "eb6db2ad-5d6c-4ed7-b4fe-1f4c9b326b14", "parameters": {"text": "={