INSERT INTO public.workflow_entity VALUES ('[Book Translation] Activate Translation Workflows [NOT USED]', true, '[{"parameters":{"httpMethod":"POST","path":"activate-translation-workflows","options":{}},"type":"n8n-nodes-base.webhook","typeVersion":1,"position":[-448,-96],"id":"webhook-node","name":"Webhook","webhookId":"activate-trans-webhook"},{"parameters":{"filters":{},"requestOptions":{}},"type":"n8n-nodes-base.n8n","typeVersion":1,"position":[-224,-96],"id":"list-workflows","name":"List Workflows","credentials":{"n8nApi":{"id":"VP4X78ps0YqOb1RP","name":"n8n account"}}},{"parameters":{"jsCode":"const EXCLUDED = [\n  ''Ручной выбор файлов'',\n  ''[Book Translation] Activate Translation Workflows'',\n  ''Test Webhook Trigger''\n];\nreturn $input.all().filter(item => {\n  const n = item.json.name || '''';\n  const isExcluded = EXCLUDED.some(ex => n.includes(ex));\n  const isArchived = item.json.isArchived === true;\n  return !isExcluded && !isArchived && item.json.active === false;\n});"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[-16,-96],"id":"filter-inactive","name":"Filter Inactive"},{"parameters":{"operation":"activate","workflowId":"={{ $json.id }}","additionalFields":{},"requestOptions":{}},"type":"n8n-nodes-base.n8n","typeVersion":1,"position":[224,-96],"id":"activate-workflow","name":"Activate Workflow","credentials":{"n8nApi":{"id":"VP4X78ps0YqOb1RP","name":"n8n account"}},"continueOnFail":true},{"parameters":{},"type":"n8n-nodes-base.manualTrigger","typeVersion":1,"position":[-640,-96],"id":"manual-trigger","name":"When clicking ''Execute workflow''"}]', '{"Webhook":{"main":[[{"node":"List Workflows","type":"main","index":0}]]},"List Workflows":{"main":[[{"node":"Filter Inactive","type":"main","index":0}]]},"Filter Inactive":{"main":[[{"node":"Activate Workflow","type":"main","index":0}]]},"When clicking ''Execute workflow''":{"main":[[{"node":"List Workflows","type":"main","index":0}]]}}', '2026-04-10 20:54:21.657+00', '2026-04-14 03:21: