INSERT INTO public.workflow_entity VALUES ('[Перевод] Перевод чанка', true, '[{"parameters":{"operation":"executeQuery","query":"SELECT * FROM document_glossary WHERE job_id IN (SELECT job_id FROM job_current);","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[-368,176],"id":"51afce0c-5c95-4860-b85b-be7d9b48dc9e","name":"Чтение глоссария","executeOnce":true,"retryOnFail":true,"alwaysOutputData":true,"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"operation":"select","schema":{"__rl":true,"mode":"list","value":"public"},"table":{"__rl":true,"value":"translate_prompts","mode":"list","cachedResultName":"translate_prompts"},"returnAll":true,"options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[-528,176],"id":"a23f9ada-511f-46a9-9663-97cb8d42a399","name":"Чтение промтов","executeOnce":true,"alwaysOutputData":true,"retryOnFail":true,"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"jsCode":"let UserPrompt = '''';\nlet SystemPrompt = '''';\nlet PostProductPrompt = '''';\n\n// User prompt\nconst roller_summary = $(''Получение rolling summary главы для промта'').first().json?.roller_summary;\nif (roller_summary && Object.keys(roller_summary)?.length) {\n  UserPrompt += `\n## КРАТКОЕ СОДЕРЖАНИЕ ПРЕДЫДУЩЕЙ ГЛАВЫ:\n${JSON.stringify(roller_summary)}\n`;\n}\n\nconst roller_summary_arc = $(''Чтение текущей арки'').first().json.summary;\nif (roller_summary_arc && Object.keys(roller_summary_arc)?.length) {\n  UserPrompt += `\n## КРАТКОЕ ОПИСАНИЕ ТЕКУЩЕЙ АРКИ:\n${JSON.stringify(roller_summary_arc)}\n`;\n}\n\nif ($(''Выбор чанка для перевода'').first().json?.prev_line) {\n  UserPrompt += `\n<CONTEXT_BEFORE>\n${$(''Выбор чанка для перевода'').first().json.prev_line}\n</CONTEXT_BEFORE>\n`;\n}\n\nUserPrompt += `\n## ПЕРЕВЕДИ СТРОГО НА РУССКИЙ:\n${$(''Выбор чанка для перевода'').first().json.chunk_text}\n`;\n\n//System Prompt\nSystemPrompt += $(''Чтение промтов'').all().find(item => item.json.name === ''BP Default'')?.json?.prompt || '''';\n\nlet glossary_text = '''';\nconst glossary = $(''Чтение глоссария'').all();\nglossary_text = glossary.map((item) => \n  Object.keys(item.json).length \n  ? `${item.json.name} = ${item.json.translate}${item.json.gender ? '' (gender: '' + (item.json.gender.toLowerCase().includes(''муж'') ? ''male'' : (item.json.gender.toLowerCase().includes(''жен'') ? ''female'' : item.json.gender)) + '').''  : ''.''}` : '''').join(''\\n'');\nif (glossary_text.length) {\n  glossary_text = \n`━━━━━━━━━━━━━━━━━━━━━━━━━━━\nГЛОССАРИЙ — ИСТОЧНИК ИСТИНЫ\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\n${glossary_text}`;\n}\nSystemPrompt = SystemPrompt.replace(''{{GLOSSARY}}'', glossary_text)\n\nlet customPrompt = $(''Чтение промтов'').all().find(item => item.json.name === ''BP BL'')?.json?.prompt || '''';\nif (customPrompt) {\n  customPrompt =`\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\nROMAN_RULES — ПРИМЕНЯТЬ ВСЕГДА. БЕЗ ИСКЛЮЧЕНИЙ.\nИМЕЮТ ПРИОРИТЕТ НАД ВСЕМИ ОСТАЛЬНЫМИ ПРАВИЛАМИ.\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\n${customPrompt}`;\n}\nSystemPrompt = SystemPrompt.replace(''{{ROMAN_RULES}}'', customPrompt)\n\nlet contestBefore_text = ''''\nif ($(''Выбор чанка для перевода'').first().json?.prev_line) {\n  contestBefore_text += `\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\nСЕКЦИЯ<CONTEXT_BEFORE>\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\nНЕ переводить.\nИспользовать только для улучшения связности основного текста.\n`\n}\nSystemPrompt = SystemPrompt.replace(''{{CONTEXT_BEFORE}}'', contestBefore_text)\n\nconst light_rag = `\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\nБАЗА ЗНАНИЙ МИРА (КОНТЕКСТ ИЗ RAG)\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\nСледующие факты извлечены из истории новеллы. Используй их для соблюдения логики событий и отношений между персонажами:\n${$(''Запрос в LightRAG'').first().json.response}\n`;\nSystemPrompt = SystemPrompt.replace(''{{LIGHT_RAG}}'', light_rag)\n\nlet isRomanRules = ''Чётко отслеживается, кто говорит и кто действует?'';\nif (customPrompt) isRomanRule