\n\nreturn { glossary_text };\n"},"type":"n8n-nodes-base.code","typeVersion":2,"position":[1488,-32],"id":"dd0b7c3b-8413-45b1-97a2-6b165602d4ed","name":"Формирование промтов для перевода1"},{"parameters":{"operation":"executeQuery","query":"UPDATE  document_chunks \n  SET \n    result_text = ''{{ $json.output.replaceAll(`''`, `''''`) }}'',\n    updated_at = now(), \n    status = ''done'' \n  WHERE \n    id = {{ $(''Start Workflow'').first().json.id_chunk }}\n  RETURNING\n    status;","options":{}},"type":"n8n-nodes-base.postgres","typeVersion":2.6,"position":[1536,192],"id":"245b7169-f945-4c98-963a-44c0708ab807","name":"Запись перевода чанка с постредактурой в бд","executeOnce":true,"retryOnFail":true,"alwaysOutputData":true,"credentials":{"postgres":{"id":"iGih4QSBWfmpkdGY","name":"Postgres account"}}},{"parameters":{"workflowId":{"__rl":true,"value":"A8zKJVQgROH1cnkv","mode":"list","cachedResultUrl":"/workflow/A8zKJVQgROH1cnkv","cachedResultName":"Постредактура"},"workflowInputs":{"mappingMode":"defineBelow","value":{"ko_text":"={{ $(''Выбор чанка для перевода'').first().json.chunk_text }}","ru_text":"={{ $(''Перевод'').first().json.output }}","rag":"={{ $(''Запрос в LightRAG'').first().json.response }}","glossary":"={{ $json.glossary_text }}"},"matchingColumns":[],"schema":[{"id":"ko_text","displayName":"ko_text","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false},{"id":"ru_text","displayName":"ru_text","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false},{"id":"glossary","displayName":"glossary","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false},{"id":"rag","displayName":"rag","required":false,"defaultMatch":false,"display":true,"canBeUsedToMatch":true,"type":"string","removed":false}],"attemptToConvertTypes":false,"convertFieldsToString":true},"options":{}},"type":"n8n-nodes-base.executeWor